class ComprehensiveEventLogger {
  static JTextArea log;
  static SimpleDateFormat fmt = new SimpleDateFormat("HH:mm:ss.SSS");
  static int eventCount = 0;

  static void logEvent(String source, String event) {
    String timestamp = fmt.format(new Date());
    log.append(String.format("[%d] %s - %s: %s\n", ++eventCount, timestamp, source, event));
    log.setCaretPosition(log.getDocument().getLength());
  }

  public static void main(String[] args) {
    JFrame frame = new JFrame("Event Logger System");
