import java.sql.*;

class TransactionDemo {
  public static void main(String[] args) {
    String url = "jdbc:mysql://localhost:3306/skillsync";
    Connection conn = null;

    try {
      conn = DriverManager.getConnection(url, "root", "");
      conn.setAutoCommit(false);

      // TODO: Execute multiple SQL statements
      // TODO: Deduct amount from one account
      // TODO: Add amount to another account
      // TODO: If all succeed, commit transaction
      // TODO: If any fails, rollback transaction
      // TODO: Use try-catch to handle exceptions

      Statement stmt = conn.createStatement();
      stmt.executeUpdate("UPDATE accounts SET balance = balance - 100 WHERE id = 1");
      stmt.executeUpdate("UPDATE accounts SET balance = balance + 100 WHERE id = 2");

      conn.commit();
      System.out.println("Transaction completed successfully!");

    } catch (SQLException e) {
      if (conn != null) {
        try {
          conn.rollback();
          System.out.println("Transaction rolled back!");
        } catch (SQLException ex) {
          ex.printStackTrace();
        }
      }
      e.printStackTrace();
    } finally {
      if (conn != null) {
        try {
          conn.close();
        } catch (SQLException e) {
          e.printStackTrace();
        }
      }
    }
  }
}

