class BatchUpdateWithTransaction {
  public static void transferPoints(int fromStudent, int toStudent, int points) {
    String url = "jdbc:mysql://localhost:3306/skillsync";
    Connection conn = null;

    try {
      conn = DriverManager.getConnection(url, "root", "");
      conn.setAutoCommit(false);

      // TODO: Deduct points from fromStudent
      // TODO: Add points to toStudent
      // TODO: Validate both operations succeed
      // TODO: Commit if all succeed, rollback if any fail

      String deductSQL = "UPDATE students SET points = points - ? WHERE id = ?";
      String addSQL = "UPDATE students SET points = points + ? WHERE id = ?";

      PreparedStatement deductStmt = conn.prepareStatement(deductSQL);
      deductStmt.setInt(1, points);
      deductStmt.setInt(2, fromStudent);
      deductStmt.executeUpdate();

      // TODO: Complete the add operation
      // TODO: Commit

      conn.commit();
      System.out.println("Transfer successful!");

    } catch (SQLException e) {
      if (conn != null) {
        try {
          conn.rollback();
          System.out.println("Transfer failed, rolled back!");
        } catch (SQLException ex) {
          ex.printStackTrace();
        }
      }
      e.printStackTrace();
    }
  }

  public static void main(String[] args) {
    transferPoints(1, 2, 50);
  }
}

import java.sql.*;
import java.io.*;

class CSVImporter {
  public static void importStudentsFromCSV(String filename) {
    String url = "jdbc:mysql://localhost:3306/skillsync";
    String sql = "INSERT INTO students (name, course, year) VALUES (?, ?, ?)";

    try (Connection conn = DriverManager.getConnection(url, "root", "");
         BufferedReader br = new BufferedReader(new FileReader(filename))) {

      PreparedStatement stmt = conn.prepareStatement(sql);
      conn.setAutoCommit(false);

      String line;
      int count = 0;

      // TODO: Skip header line
      br.readLine();

      while ((line = br.readLine()) != null) {
        // TODO: Split CSV line by comma
        // TODO: Parse values and set parameters
        // TODO: Add to batch
        // TODO: Execute batch every 100 records
        String[] data = line.split(",");
        stmt.setString(1, data[0]);
        stmt.setString(2, data[1]);
        stmt.setInt(3, Integer.parseInt(data[2]));
        stmt.addBatch();
        count++;

        if (count % 100 == 0) {
          stmt.executeBatch();
        }
      }

      stmt.executeBatch(); // Execute remaining
      conn.commit();
      System.out.println("Imported " + count + " records!");

    } catch (Exception e) {
      e.printStackTrace();
    }
  }

  public static void main(String[] args) {
    importStudentsFromCSV("students.csv");
  }
}

