    String sql = "SELECT id, name, course, year FROM students";

    try (Connection conn = DriverManager.getConnection(url, "root", "");
         Statement stmt = conn.createStatement();
         ResultSet rs = stmt.executeQuery(sql);
         PrintWriter writer = new PrintWriter(new FileWriter(filename))) {

      // TODO: Write CSV header
      writer.println("ID,Name,Course,Year");

      // TODO: Write data rows
      while (rs.next()) {
        // TODO: Format data with commas
        // TODO: Handle values containing commas or quotes
        String line = rs.getInt("id") + "," +
                     rs.getString("name") + "," +
                     rs.getString("course") + "," +
                     rs.getInt("year");
        writer.println(line);
      }

      System.out.println("Export completed!");

    } catch (Exception e) {
      e.printStackTrace();
    }
  }

  public static String escapeCSV(String value) {
    // TODO: Escape values containing commas or quotes
    if (value.contains(",") || value.contains("\"")) {
      return "\"" + value.replace("\"", "\"\"") + "\"";
    }
    return value;
  }

  public static void main(String[] args) {
    exportStudentsToCSV("students_export.csv");
  }
