    String url = "jdbc:mysql://localhost:3306/skillsync";

    // TODO: Use INSERT ... ON DUPLICATE KEY UPDATE
    // TODO: If ID exists, update; if not, insert
    String sql = "INSERT INTO students (id, name, course, year) " +
                 "VALUES (?, ?, ?, ?) " +
                 "ON DUPLICATE KEY UPDATE name = ?, course = ?, year = ?";

    try (Connection conn = DriverManager.getConnection(url, "root", "")) {
      PreparedStatement stmt = conn.prepareStatement(sql);

      // Set INSERT values
      stmt.setInt(1, id);
      stmt.setString(2, name);
      stmt.setString(3, course);
      stmt.setInt(4, year);

      // Set UPDATE values
      stmt.setString(5, name);
      stmt.setString(6, course);
      stmt.setInt(7, year);

      int result = stmt.executeUpdate();

      if (result == 1) {
        System.out.println("Inserted new record");
      } else if (result == 2) {
        System.out.println("Updated existing record");
      }

    } catch (SQLException e) {
      e.printStackTrace();
    }
  }

  public static void main(String[] args) {
    upsertStudent(1, "Juan Dela Cruz", "BSIT", 3);
    upsertStudent(1, "Juan D. Cruz", "BSCS", 4); // Updates existing
  }
}

