import java.sql.*;
import java.util.logging.*;

class EnhancedRethrowDemo {
  static Logger logger = Logger.getLogger(EnhancedRethrowDemo.class.getName());

  public static void updateStudentScore(int studentId, int score) throws SQLException {
    String url = "jdbc:mysql://localhost:3306/skillsync";

    try {
      Connection conn = DriverManager.getConnection(url, "root", "");
      String sql = "UPDATE students SET score = ? WHERE id = ?";
      PreparedStatement stmt = conn.prepareStatement(sql);
      stmt.setInt(1, score);
      stmt.setInt(2, studentId);
      stmt.executeUpdate();

    } catch (SQLException e) {
      // TODO: Log the error with context
      logger.severe("Failed to update score for student " + studentId);
      logger.severe("SQL State: " + e.getSQLState());
      logger.severe("Error Code: " + e.getErrorCode());

      // TODO: Rethrow the exception for caller to handle
      throw e;
    }
  }

  public static void main(String[] args) {
