import java.sql.*;

class GracefulDegradationDemo {
  static Connection primaryConn = null;
  static Connection backupConn = null;

  public static Connection getConnection() {
    // TODO: Try primary database first
    try {
      if (primaryConn == null || primaryConn.isClosed()) {
        primaryConn = DriverManager.getConnection(
          "jdbc:mysql://localhost:3306/skillsync", "root", "");
        System.out.println("Connected to primary database");
      }
      return primaryConn;

    } catch (SQLException e) {
      System.out.println("Primary database unavailable, trying backup...");

      // TODO: Fallback to backup database
      try {
        if (backupConn == null || backupConn.isClosed()) {
          backupConn = DriverManager.getConnection(
            "jdbc:mysql://backup-server:3306/skillsync", "root", "");
          System.out.println("Connected to backup database");
        }
        return backupConn;

      } catch (SQLException backupEx) {
        System.err.println("Both primary and backup databases unavailable!");
        return null;
      }
    }
  }

  public static String getStudentName(int id) {
    Connection conn = getConnection();

    if (conn == null) {
      // TODO: Return cached or default value
      System.out.println("Using cached data");
      return "Student " + id + " (cached)";
    }

    try {
      String sql = "SELECT name FROM students WHERE id = ?";
      PreparedStatement stmt = conn.prepareStatement(sql);
      stmt.setInt(1, id);
      ResultSet rs = stmt.executeQuery();

      if (rs.next()) {
        return rs.getString("name");
      }
    } catch (SQLException e) {
      System.out.println("Query failed, using default");
    }

    return "Unknown Student";
  }

  public static void main(String[] args) {
    String name = getStudentName(1);
    System.out.println("Student name: " + name);
  }
}

import java.sql.*;
import java.time.*;

class CircuitBreaker {
  enum State { CLOSED, OPEN, HALF_OPEN }

  private State state = State.CLOSED;
  private int failureCount = 0;
  private int failureThreshold = 5;
  private LocalDateTime openedAt;
  private Duration timeout = Duration.ofSeconds(30);

  public boolean isOpen() {
    // TODO: If state is OPEN and timeout expired, transition to HALF_OPEN
    if (state == State.OPEN) {
      if (Duration.between(openedAt, LocalDateTime.now()).compareTo(timeout) > 0) {
        state = State.HALF_OPEN;
        System.out.println("Circuit HALF_OPEN - trying recovery");
      }
    }
    return state == State.OPEN;
  }

  public void recordSuccess() {
    // TODO: Reset failure count and close circuit
    failureCount = 0;
    state = State.CLOSED;
    System.out.println("Circuit CLOSED - operations normal");
  }

  public void recordFailure() {
    // TODO: Increment failure count
    failureCount++;

    // TODO: If threshold exceeded, open circuit
    if (failureCount >= failureThreshold) {
      state = State.OPEN;
      openedAt = LocalDateTime.now();
      System.out.println("Circuit OPEN - too many failures");
    }
  }
}

class DatabaseService {
  static CircuitBreaker breaker = new CircuitBreaker();

  public static void queryDatabase() {
    // TODO: Check if circuit is open
    if (breaker.isOpen()) {
      System.out.println("Circuit is OPEN - request rejected");
      return;
    }

    try {
      Connection conn = DriverManager.getConnection(
        "jdbc:mysql://localhost:3306/skillsync", "root", "");

      // Successful operation
      breaker.recordSuccess();

    } catch (SQLException e) {
      breaker.recordFailure();
      System.out.println("Database operation failed");
    }
  }

  public static void main(String[] args) {
    for (int i = 0; i < 10; i++) {
      queryDatabase();
    }
  }
}

class Student {
  private int id;
  private String name;
  private int age;
  private String course;

  public Student(int id, String name, int age, String course) {
    // TODO: Use assertions for preconditions
    assert id > 0 : "Student ID must be positive";
    assert name != null && !name.isEmpty() : "Name cannot be null or empty";
    assert age >= 15 && age <= 100 : "Age must be between 15 and 100";
    assert course != null : "Course cannot be null";

    this.id = id;
    this.name = name;
    this.age = age;
    this.course = course;
  }

  public void updateAge(int newAge) {
    // TODO: Defensive validation
    if (newAge < 15 || newAge > 100) {
      throw new IllegalArgumentException("Invalid age: " + newAge);
    }

    // TODO: Assert invariants
    assert this.age < newAge : "Age can only increase";

    this.age = newAge;

    // TODO: Post-condition assertion
    assert this.age == newAge : "Age not updated correctly";
  }

  public int calculateDiscount() {
    // TODO: Method invariants
    assert age > 0 : "Age must be set";

    int discount = 0;
    if (age < 18) discount = 20;
    else if (age >= 60) discount = 30;
    else discount = 10;

    // TODO: Post-condition
    assert discount >= 0 && discount <= 100 : "Discount must be 0-100%";

    return discount;
  }

  public static void main(String[] args) {
    // Enable assertions: java -ea ClassName

    try {
      Student s1 = new Student(1, "Juan", 20, "BSIT");
      s1.updateAge(21);
      System.out.println("Discount: " + s1.calculateDiscount() + "%");

      // This will trigger assertion error if -ea is enabled
      Student s2 = new Student(-1, "", 5, null);

    } catch (AssertionError e) {
      System.out.println("Assertion failed: " + e.getMessage());
    } catch (IllegalArgumentException e) {
      System.out.println("Invalid argument: " + e.getMessage());
    }
  }
}

